1	export type Cell = [number, number];
2	
3	const SURVIVAL_MIN_NEIGHBORS = 2;
4	const SURVIVAL_MAX_NEIGHBORS = 3;
5	
6	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
7	  [-1, -1], [-1, 0], [-1, 1],
8	  [0, -1],           [0, 1],
9	  [1, -1],  [1, 0],  [1, 1],
10	];
11	
12	function cellKey(x: number, y: number): string {
13	  return `${x},${y}`;
14	}
15	
16	function countLiveNeighbors(x: number, y: number, liveSet: Set<string>): number {
17	  return NEIGHBOR_OFFSETS.filter(([dx, dy]) => liveSet.has(cellKey(x + dx, y + dy))).length;
18	}
19	
20	function survives(neighborCount: number): boolean {
21	  return neighborCount === SURVIVAL_MIN_NEIGHBORS || neighborCount === SURVIVAL_MAX_NEIGHBORS;
22	}
23	
24	const BIRTH_NEIGHBOR_COUNT = 3;
25	
26	function deadNeighborsOf(cells: Cell[], liveSet: Set<string>): Map<string, Cell> {
27	  const deadNeighbors = new Map<string, Cell>();
28	  for (const [x, y] of cells) {
29	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
30	      const [nx, ny] = [x + dx, y + dy];
31	      const key = cellKey(nx, ny);
32	      if (!liveSet.has(key)) deadNeighbors.set(key, [nx, ny]);
33	    }
34	  }
35	  return deadNeighbors;
36	}
37	
38	function isBorn(cell: Cell, liveSet: Set<string>): boolean {
39	  return countLiveNeighbors(cell[0], cell[1], liveSet) === BIRTH_NEIGHBOR_COUNT;
40	}
41	
42	export function nextGeneration(cells: Cell[]): Cell[] {
43	  const liveSet = new Set(cells.map(([x, y]) => cellKey(x, y)));
44	  const survivors = cells.filter(([x, y]) => survives(countLiveNeighbors(x, y, liveSet)));
45	  const births = [...deadNeighborsOf(cells, liveSet).values()].filter((cell) => isBorn(cell, liveSet));
46	  return [...survivors, ...births];
47	}
