1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single cell dies from underpopulation — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent cells both die from underpopulation — [(0,1), (1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("live cell with 2 neighbors survives (Rule 2) — cell with exactly 2 live neighbors stays alive", () => {
15	    // L-shape: (0,0), (1,0), (0,1). Cell (0,0) has 2 neighbors: (1,0) and (0,1). It should survive.
16	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
17	    expect(result).toContainEqual([0, 0]);
18	  });
19	  it("live cell with 4 neighbors dies from overpopulation (Rule 3) — center cell dies", () => {
20	    // Cell (1,1) with 4 neighbors at (0,1), (2,1), (1,0), (1,2). Center should die.
21	    const result = nextGeneration([[1, 1], [0, 1], [2, 1], [1, 0], [1, 2]]);
22	    expect(result).not.toContainEqual([1, 1]);
23	  });
24	  it("dead cell with exactly 3 neighbors becomes alive (Rule 4)", () => {
25	    // L-shape: live cells at (0,0),(1,0),(0,1). Dead cell (1,1) has 3 live neighbors → becomes alive.
26	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
27	    expect(result).toContainEqual([1, 1]);
28	  });
29	  it("block still life remains unchanged — [(0,0),(1,0),(0,1),(1,1)] → same", () => {
30	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
31	    const result = nextGeneration(block);
32	    expect(result).toHaveLength(4);
33	    expect(result).toEqual(expect.arrayContaining(block));
34	  });
35	  it.todo("vertical blinker becomes horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]");
36	  it.todo("handles negative coordinates correctly");
37	});
