function neighborsOf([x, y]: Cell): Cell[] {
  return NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
}

function deadNeighborsOf(cells: Cell[], liveSet: Set<string>): Cell[] {
  const allNeighbors = cells.flatMap(neighborsOf);
  const deadByKey = new Map<string, Cell>();
  for (const cell of allNeighbors) {
    const key = cellKey(cell[0], cell[1]);
    if (!liveSet.has(key)) deadByKey.set(key, cell);
  }
  return [...deadByKey.values()];
}

